insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('leopar-gecko','Leopar Gecko','Eublepharis macularius','kertenkele','Başlangıç','15–20 yıl','20–25 cm','60×40×40 cm (tek birey)','Sıcak bölge 28–32°C · serin bölge 24–26°C · gece 20–22°C','%30–40 (deri değişiminde nem kutusu %70–80)','Çekirge, dubia hamam böceği, un kurdu · haftada 2–3 öğün · kalsiyum + D3 tozu şart','["Leopar gecko, Pakistan ve Afganistan''ın kurak bölgelerine özgü, gece aktif bir kertenkeledir. Sakin mizacı, düşük bakım maliyeti ve dayanıklılığı sayesinde dünyada en çok beslenen ilk egzotik hayvanlardan biridir ve yeni başlayanlar için en iyi seçenektir.","Çoğu geckonun aksine göz kapakları vardır ve duvara tırmanamaz; bu yüzden teraryumun yatay geniş olması yeterlidir. Isıtma alttan ısıtıcı matla yapılmalı, ışıklı ısı taşı kullanılmamalıdır (yanık riski). Substrat olarak yavrularda kağıt havlu, yetişkinlerde kaya/karo veya özel toprak karışımı önerilir; kalsiyum kumu yutulursa tıkanıklık yapar.","Kuyruğu yağ deposudur; sağlıklı bireyde dolgun olmalıdır. Tehdit altında kuyruğunu bırakabilir (otonomi) — yenisi çıkar ama eskisi kadar düzgün olmaz. Aynı teraryumda iki erkek asla bir arada tutulmaz."]'::jsonb,'["Deri değişimi öncesi renk matlaşır; nem kutusu ekleyin","Parmak uçlarında deri kalıntısı kalırsa ılık suyla yumuşatın","Kalsiyum eksikliği (MBD) titreme ve yumuşak çene ile belli olur"]'::jsonb,false,0) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('kron-gecko','Kron Gecko (Crested)','Correlophus ciliatus','kertenkele','Başlangıç','15–20 yıl','18–22 cm','45×45×60 cm dikey','22–26°C (28°C üzeri tehlikeli!)','%60–80 · günde 1–2 sisleme','Hazır meyve püresi mama (CGD) + haftada 1–2 böcek','["Yeni Kaledonya''ya özgü kron gecko, 1994''te yeniden keşfedilene kadar nesli tükendi sanılıyordu. Bugün üretimi en yaygın türlerden biridir. Ağaçta yaşar, bu yüzden dikey teraryum ve bolca tırmanma dalı ister.","En büyük avantajı çoğu evde ek ısıtma gerektirmemesidir — oda sıcaklığı idealdir; hatta 28°C üzeri ısı stresi yaratır. Hazır toz mamalar (meyve püresi kıvamında sulandırılır) beslenmeyi çok kolaylaştırır.","Kuyruğunu bırakırsa leopar geckonun aksine yenisi çıkmaz; ama bu sağlık sorunu yaratmaz, doğadaki yetişkinlerin çoğu kuyruksuzdur."]'::jsonb,'["Gece aktif olduğundan gündüz saklanacak yaprak örtüsü sağlayın","Cam kenarlarından su damlacıklarını içer; su kabını yine de bulundurun","Zıplayarak hareket eder — elde tutarken düşmeye dikkat"]'::jsonb,false,1) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('sakalli-ejder','Sakallı Ejder','Pogona vitticeps','kertenkele','Başlangıç–Orta','10–15 yıl','40–60 cm','120×60×60 cm','Güneşlenme noktası 38–42°C · serin bölge 26–30°C','%30–40','Yavru: %80 böcek %20 sebze · Yetişkin: %20 böcek %80 sebze-yeşillik','["Avustralya''nın kurak iç bölgelerinden gelen sakallı ejder, insanla etkileşime en açık sürüngenlerden biridir. Tehdit algıladığında çenesinin altındaki ''sakalı'' kabartıp karartır — adı buradan gelir.","Gündüz aktif (diürnal) olduğu için güçlü aydınlatma ister: %10–12 UVB floresan olmadan kalsiyum metabolize edemez ve ölümcül olabilen metabolik kemik hastalığı (MBD) gelişir. UVB tüpleri 6–12 ayda bir yenilenmelidir.","Kış aylarında brumasyon (kış uyuşukluğu) yaşayabilir; iştah azalır, hareket yavaşlar. Bu normaldir ama önce parazit kontrolü yaptırmak güvenlidir. Kol ve el sallama gibi ilginç sosyal davranışları vardır."]'::jsonb,'["Işıklar günde 12–14 saat açık kalmalı","Kalsiyumsuz ıspanak yerine roka, hindiba, kabak önerilir","Ateş böceği kesinlikle zehirlidir, asla vermeyin"]'::jsonb,false,2) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('top-piton','Top Piton (Ball Python)','Python regius','yilan','Başlangıç','20–30 yıl (kayıtlarda 45+)','100–150 cm','90×45×45 cm (yetişkin)','Sıcak bölge 31–33°C · serin bölge 26–28°C','%50–60 (deri değişiminde %70)','Donmuş-çözülmüş fare/sıçan · yavruda haftada 1, yetişkinde 10–14 günde 1','["Batı Afrika kökenli top piton, tehdit altında başını ortaya alıp top gibi kıvrıldığı için bu adı almıştır. Zehirsizdir, uysal yapısı ve yüzlerce renk mutasyonu (morph) ile dünyanın en popüler evcil yılanıdır. Pastel, Banana, Piebald, Clown gibi morphların fiyatı birkaç bin liradan yüz binlerce liraya uzanır.","En bilinen sorunu yem reddidir: stres, yanlış sıcaklık, deri değişimi veya mevsimsel döngü sebebiyle haftalarca yemek yemeyebilir. Sağlıklı bir yetişkin bunu rahat tolere eder; panik yapmadan koşulları kontrol edin.","Kaçış ustasıdır — kapak mutlaka kilitli olmalı. Her iki tarafta (sıcak/serin) birer saklanma kutusu güven duygusu için şarttır. Canlı yem yerine donmuş-çözülmüş yem hem güvenli hem etiktir."]'::jsonb,'["Yemden 48 saat sonra elle tutmayın (regürjitasyon riski)","Deri tek parça çıkmalı; parça parça çıkıyorsa nem düşüktür","Su kabı gövdesinin sığacağı boyutta olsun"]'::jsonb,false,3) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('misir-yilani','Mısır Yılanı (Corn Snake)','Pantherophis guttatus','yilan','Başlangıç','15–20 yıl','120–150 cm','90×45×45 cm','Sıcak bölge 28–30°C · serin bölge 22–24°C','%40–50','Donmuş-çözülmüş fare · 7–10 günde 1','["Kuzey Amerika kökenli mısır yılanı, adını mısır ambarlarında kemirgen avlarken görülmesinden alır. Zehirsiz, meraklı ve neredeyse hiç ısırmayan yapısıyla ''ilk yılan'' denince akla gelen türdür.","Top pitona göre daha ince ve hareketlidir, yem reddi sorunu neredeyse hiç görülmez. Amelanistic, Snow, Lavender gibi onlarca renk varyasyonu üretilmiştir.","Tırmanmayı sever; dallar ve yarı nemli saklanma kutusu ideal ortam sağlar. Türkiye''de evde bakımına izin verilen zehirsiz türlerdendir."]'::jsonb,'["Yavrular ilk aylarda küçük kutularda daha az stres yaşar","Kaçmaya çok meyillidir; en küçük delik bile yeterli","Aktif saatleri alacakaranlıktır"]'::jsonb,false,4) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('boga-yilani','Boğa Yılanı (Bull Snake)','Pituophis catenifer sayi','yilan','Orta','15–20 yıl','150–250 cm','120×60×60 cm','Sıcak bölge 28–31°C · serin bölge 22–24°C','%40–50','Donmuş-çözülmüş sıçan · 10–14 günde 1','["Kuzey Amerika''nın en büyük yılanlarından boğa yılanı, tehdit edildiğinde çıngıraklı yılanı taklit ederek tıslar ve kuyruğunu titretir — ama bu tamamen blöftür, zehirsizdir.","Mısır yılanının iri kuzeni sayılır; daha fazla alan ve daha güçlü kapak ister. Doğru sosyalleştirilirse uysallaşır ancak yavruları savunmacı olabilir.","Kemirgen kontrolünde doğal denge unsuru olan bu tür, tarım alanlarının dostudur."]'::jsonb,'["Tıslaması korkutucu ama zararsızdır; sakin ve düzenli elle tutma ile azalır","Derin substrat ister; kazmayı sever","Güçlü bir yeme refleksi vardır, maşayla besleyin"]'::jsonb,false,5) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('yemen-bukalemunu','Yemen Bukalemunu','Chamaeleo calyptratus','kertenkele','İleri','5–8 yıl','35–60 cm','60×60×120 cm tel (mesh) kafes','Güneşlenme 32–35°C · ortam 24–28°C · gece 18–21°C','%50–70 · damla sulama sistemi','Çekirge, sinek, hamam böceği + az miktarda yaprak · kalsiyum takviyesi','["Başındaki miğfere benzer çıkıntıyla tanınan Yemen bukalemunu, bukalemunlar arasında bakımı en kolay olanıdır — ama yine de deneyim ister. Renk değiştirmesi kamuflajdan çok ruh hali ve ısı düzenlemesiyle ilgilidir.","Cam teraryum yerine havalandırmalı tel kafes şarttır; durgun hava solunum enfeksiyonuna yol açar. Su kabından su içmez — yapraklara damlayan suyu yalar, bu yüzden otomatik damlatma veya sisleme sistemi hayati önem taşır.","Elle tutulmaktan hoşlanmaz, stres hassasiyeti yüksektir. İzlemesi harika, dokunması sınırlı bir hayvandır. Kendi yansımasını rakip sanabilir; kafesi aynadan uzak tutun."]'::jsonb,'["UVB aydınlatma olmazsa olmaz","Dişiler çiftleşmeden de yumurtlar; yumurtlama kabı hazır olmalı","Gözlerinin ayrı ayrı hareket etmesi tamamen normaldir"]'::jsonb,false,6) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('mavi-dilli-skink','Mavi Dilli Skink','Tiliqua scincoides','kertenkele','Orta','15–20 yıl','45–60 cm','120×60×60 cm','Güneşlenme 33–35°C · serin bölge 24–28°C','%40–60','Omnivor: %40 protein (böcek, haşlanmış yumurta) · %50 sebze · %10 meyve','["Avustralya kökenli bu iri kertenkele, tehdit algıladığında parlak mavi dilini göstererek düşmanını şaşırtır. Kısa bacaklı, uzun gövdeli yapısı ve sakin karakteriyle ''köpek gibi kertenkele'' diye anılır.","Omnivordur: kaliteli konserve köpek/kedi maması bile ara öğün olarak (az miktarda) kullanılabilir. Çeşitlilik uzun ömrün anahtarıdır.","Zemin hayvanıdır; tırmanmaz ama kazmayı sever, 10–15 cm derin substrat idealdir. Doğru sosyalleştirilirse elde tutulmaya çok iyi uyum sağlar."]'::jsonb,'["Yalnız yaşar; iki birey ciddi kavga eder","UVB aydınlatma kemik sağlığı için gereklidir","Kilo almaya eğilimlidir; yağlı yemleri sınırlayın"]'::jsonb,false,7) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('aksolotl','Aksolotl','Ambystoma mexicanum','amfibi','Orta','10–15 yıl','25–30 cm','80+ litre akvaryum (tek birey)','Su 16–18°C (20°C üzeri kronik stres!)','Tamamen sucul','Canlı/donmuş solucan, aksolotl peleti, karides · yetişkinde 2–3 günde 1','["Meksika''daki Xochimilco göllerine özgü aksolotl, ergenleşmeden yaşayan bir semenderdir (neoteni): dış solungaçlarını ömür boyu korur. Kol, bacak, hatta kalp ve beyin dokusunu yenileyebilme yeteneğiyle bilim dünyasının en çok araştırdığı canlılardandır. Doğada kritik tehlikededir; akvaryumlardakiler tamamen üretimdir.","En kritik konu su sıcaklığıdır: 20°C üzerinde bağışıklığı çöker. Türkiye yazlarında soğutucu fan veya chiller çoğu evde gerekir. Amonyağa çok duyarlıdır — döngüsü oturmuş, yavaş akışlı filtreli akvaryum şarttır.","Çakıl taşı yutarak bağırsak tıkanıklığı yaşayabilir; taban ya çıplak ya da çok ince kum olmalıdır. Balıklarla veya birbirleriyle (solungaç ısırma) bir arada tutulması önerilmez."]'::jsonb,'["Klorlu musluk suyu şartlandırıcıyla arıtılmalı","Akvaryum ışığı loş olmalı; parlak ışıktan kaçınır","Elle asla tutmayın; cildi çok naziktir, kepçe kullanın"]'::jsonb,false,8) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('pacman-kurbagasi','Pacman Kurbağası','Ceratophrys ornata','amfibi','Başlangıç','7–10 yıl','10–15 cm','40×30 cm (alçak olabilir)','24–28°C','%60–80','Çekirge, solucan, hamam böceği · haftada 2–3 · yetişkine ayda 1 pinky fare','["Güney Amerika kökenli bu tombul kurbağa, ağzının vücuduna oranı ve yuvarlak silueti ile oyun karakteri Pac-Man''e benzetilir. Hayatının çoğunu toprağa yarı gömülü, pusuda geçirir.","Bakımı son derece basittir: alçak bir teraryum, 5–7 cm nemli hindistan cevizi toprağı ve sığ bir su kabı yeterlidir. Hareketsizliği hastalık değil, doğasıdır.","Önüne gelen her şeyi ısırma refleksi vardır — buna parmaklar da dahil. Zehirli değildir ama küçük dişleri iz bırakabilir; maşayla beslemek en doğrusudur. Obeziteye çok yatkındır."]'::jsonb,'["Klorsuz su kullanın; deriden emilim yapar","İki pacman asla bir arada tutulmaz (birbirini yer)","Islak elle veya eldivenle dokunun"]'::jsonb,false,9) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('kirmizi-diz-tarantula','Meksika Kırmızı Diz Tarantulası','Brachypelma hamorii','eklem','Başlangıç (eklem bacaklı)','Dişi 25–30 yıl · erkek 5–10 yıl','12–15 cm bacak açıklığı','30×30×30 cm (yatay)','22–28°C','%60–70','Çekirge, hamam böceği · yetişkinde 2–3 haftada 1–2 böcek','["Siyah gövdesi ve turuncu-kırmızı diz bantlarıyla dünyanın en tanınan tarantulası. Sakin, yavaş ve dayanıklı yapısı onu ilk tarantula için standart seçenek yapar. CITES Ek-II''de listelidir; yalnızca üretim bireyler yasal ticarete konu olabilir.","Zehri arı sokması şiddetindedir ama asıl savunması karnındaki ürtiker (kaşındırıcı) tüylerdir: tehdit hissederse bunları havaya fırlatır; cilt ve göz tahrişi yapar. Teraryum temizliğinde dikkat gerekir.","Deri değişimi öncesi haftalarca yem reddedebilir ve sırtüstü yatar — bu ölüm değil, tam tersine büyüme işaretidir; asla dokunmayın. Yeni deri sertleşene kadar (1–2 hafta) yem vermeyin."]'::jsonb,'["Düşme tarantulalar için ölümcüldür; yüksekten tutmayın","Su kabı küçük ve sığ olmalı","Substrat 8–10 cm; yuva kazmayı sever"]'::jsonb,false,10) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('imparator-akrep','İmparator Akrep','Pandinus imperator','eklem','Orta','6–8 yıl','15–20 cm','40×30 cm','26–30°C','%70–80','Çekirge, hamam böceği · haftada 1–2','["Batı Afrika yağmur ormanlarından gelen imparator akrep, dünyanın en büyük akreplerinden biridir ama görünüşünün aksine zehri arı sokması düzeyindedir — asıl gücü iri kıskaçlarındadır. CITES Ek-II kapsamındadır.","Nemli ve derin (10+ cm) substrat ister; gece aktiftir ve gündüzünü kaya altında/yuvasında geçirir. UV ışık altında mavi-yeşil floresan parlar; bu, gözlem için eğlenceli ve zararsız bir özelliktir.","Sosyal sayılabilecek nadir akreplerdendir; yeterli alan ve saklanma noktası varsa grup halinde tutulabilir. Yine de yavrularla yetişkinler ayrılmalıdır."]'::jsonb,'["Elle tutulması önerilmez; kıskaç sıkması ciddi acı verir","Sisleme ile nem korunmalı","Doğum yapan dişi ayrı tutulmalı"]'::jsonb,false,11) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('pigme-kirpi','Pigme Kirpi','Atelerix albiventris','memeli','Başlangıç','4–6 yıl','15–20 cm','80×50 cm kafes + koşu tekeri','24–27°C (20°C altı tehlikeli hibernasyon riski)','Normal oda nemi','Yüksek proteinli kedi maması + böcek + az meyve-sebze','["Afrika pigme kirpisi, evcil olarak üretilen melez bir türdür. Gece aktiftir ve doğada bir gecede kilometrelerce yol yürür — bu yüzden deliksiz (ayak takılmayan) bir koşu tekeri kafesin en önemli parçasıdır.","Yeni kokularla karşılaşınca köpüklü tükürüğünü dikenlerine sürer (''anointing''); bu tuhaf davranış tamamen normaldir. Yalnız yaşamayı sever; iki kirpi aynı kafeste tutulmaz.","En kritik nokta sıcaklıktır: 20°C altında yarı-hibernasyona girer ve bu evcil bireyler için ölümcül olabilir. Kafes soğuk zeminden ve cereyandan uzak olmalı, gerekirse seramik ısıtıcı eklenmelidir."]'::jsonb,'["Dikenler avuç içine batmaz; kendinden emin tutuş öğrenin","Ayda 1–2 ılık su banyosu yeterli","Obeziteye yatkın; yağlı mamadan kaçının"]'::jsonb,false,12) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('sugar-glider','Sugar Glider','Petaurus breviceps','memeli','İleri','10–15 yıl','25–30 cm (kuyrukla)','60×60×90 cm+ dikey kafes','24–28°C','Normal oda nemi','HPW benzeri nektar karışımı + meyve + böcek · kalsiyum dengesi kritik','["Avustralya ve Yeni Gine kökenli bu keseli memeli, kollarıyla bacakları arasındaki zarla 50 metreye kadar süzülebilir. Kanguruyla akrabadır; yavrusunu kesesinde taşır.","En önemli kural: asla tek beslenmez. Son derece sosyal bir koloniden gelir; yalnız kalan birey depresyona girer ve kendine zarar verebilir. En az çift (tercihen aynı cinsiyet veya kısırlaştırılmış) alınmalıdır.","Gece aktiftir ve havlama benzeri sesler çıkarır; hafif uykulu insanlar için doğru tercih değildir. ''Bonding kesesi'' ile gün içinde üzerinizde taşıyarak güçlü bağ kurabilirsiniz. Kalsiyum/fosfor dengesi bozulursa arka ayak felci (HLP) gelişir; beslenme planı ciddiyet ister."]'::jsonb,'["Kafeste süzülme mesafesi için yükseklik önemli","Sabah kafese dönen hayvanı rahatsız etmeyin","Egzotik hayvan veterineri desteği şart"]'::jsonb,false,13) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('yunan-kaplumbagasi','Yunan Kaplumbağası (Tosbağa)','Testudo graeca','kaplumbaga','Orta','50–100+ yıl','20–30 cm','Dış mekan bahçe alanı veya 120×60 cm iç mekan masa','Güneşlenme 32–35°C · UVB şart','%40–60','Yabani otlar, hindiba, roka, deve dikeni · meyve çok az · hayvansal gıda asla','["⚠️ ÖNEMLİ YASAL UYARI: Yunan kaplumbağası Türkiye''nin doğal (yerli) türüdür, CITES Ek-II''de listelidir ve doğadan toplanması, satılması, satın alınması 4915 sayılı Kara Avcılığı Kanunu ile YASAKTIR. Bu rehber yalnızca halihazırda bakmakta olduğunuz veya yasal belgeli bireyler için bilgilendirme amaçlıdır. SürüngenMarket''te bu türün satış ilanı yayınlanamaz.","Onlarca yıl yaşayan bu tür bir ''ömürlük taahhüttür'' ve en iyi bahçede, doğal güneş ışığında yaşar. İç mekanda bakılacaksa güçlü UVB ve ısı lambası zorunludur; akvaryum/cam kap kesinlikle uygun değildir (hava sirkülasyonu ve alan yetersiz).","Beslenmenin %90''ı lifli yabani yeşilliklerden oluşmalıdır. Marul gibi besinsiz, meyve gibi şekerli gıdalar kabuk deformasyonuna yol açar. Doğal hibernasyon (kış uykusu) sağlıklı bireyler için normaldir ama veteriner kontrolü önerilir."]'::jsonb,'["Sokakta bulduğunuz kaplumbağayı eve almayın; doğada bırakın","Kabuk yumuşaması ciddi hastalık işaretidir","Islak mama/ekmek/süt asla verilmez"]'::jsonb,true,14) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('sisman-kuyruklu-gecko','Afrika Şişman Kuyruklu Geckosu','Hemitheconyx caudicinctus','kertenkele','Başlangıç','15–25 yıl','18–25 cm','60×40×40 cm','Sıcak bölge 30–32°C · serin bölge 24–26°C','%50–60 (leopar geckodan daha nemli)','Çekirge, dubia, un kurdu · haftada 2–3 öğün · kalsiyum+D3','["Batı Afrika''nın leopar geckosu sayılır: aynı aileden, aynı boyda, göz kapaklı ve zemin yaşayan bir türdür. Leopar geckodan daha sakin, hatta daha ''tembel'' mizaçlıdır; elle tutulmaya kolay alışır.","En önemli fark nem ihtiyacıdır: kurak değil, yarı nemli savanadan geldiği için nemli bir saklanma kutusu (moss/yosun dolu) şarttır; aksi halde deri değişimi ve parmak sorunları yaşar. Alttan ısıtma matı ile ısıtılır, kızgın kaya kullanılmaz."]'::jsonb,'["Nemli saklanma kutusu her zaman bulundurulmalı","Kuyruğu bırakabilir; yenisi çıkar ama farklı görünür","İki erkek asla bir arada tutulmaz"]'::jsonb,false,15) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('gargoyle-gecko','Gargoyle Gecko','Rhacodactylus auriculatus','kertenkele','Başlangıç','15–20 yıl','20–25 cm','45×45×60 cm dikey','22–27°C, oda sıcaklığı ideal','%50–70, akşam sisleme','Hazır meyve püresi mama (CGD) + haftada 1–2 böcek','["Yeni Kaledonya kökenli gargoyle gecko, başındaki boynuzsu çıkıntılardan adını alır. Kron geckoya çok benzer bakım ister ama ondan daha dayanıklı ve kavgacıdır. Ek ısıtma çoğu evde gerekmez.","Kron geckonun aksine kuyruğunu bıraksa bile yenisini kısmen yeniler. Avcı içgüdüsü güçlüdür; küçük geckoları bile yiyebileceği için tek başına barındırılır. Hazır toz mamalar beslenmeyi çok kolaylaştırır."]'::jsonb,'["Dikey teraryum ve tırmanma dalları şart","Tek başına barındırın; kanibal olabilir","28°C üzeri ısı stresi yaratır"]'::jsonb,false,16) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('leachianus-gecko','Leachianus Gecko (Dev Gecko)','Rhacodactylus leachianus','kertenkele','Orta','20–30 yıl','30–43 cm','60×45×90 cm dikey','22–27°C','%60–70','Hazır meyve mama (CGD) + böcek, ara sıra pinky','["Dünyanın en büyük geckosu olan leachianus, Yeni Kaledonya''ya özgüdür ve ''köpek havlamasına'' benzer sesler çıkarır. İri, ağır ve uzun ömürlüdür; adeta bir yatırım hayvanıdır.","Elle tutulmaya alışabilir ama ısırığı güçlüdür. Yetişkinler genelde tek yaşar; çift oluşturmak deneyim ister. Bölgeseldir, teraryumunu ''kendi evi'' olarak sahiplenir."]'::jsonb,'["Güçlü ısırır; yavaş ve sakin yaklaşın","Uzun ömür = uzun taahhüt","Bölgesel; teraryum düzenini sık değiştirmeyin"]'::jsonb,false,17) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('tokay-gecko','Tokay Gecko','Gekko gecko','kertenkele','Orta–İleri','10–15 yıl','25–35 cm','45×45×60 cm dikey','26–32°C','%60–80','Çekirge, hamam böceği, ara sıra pinky','["Güneydoğu Asya''nın gösterişli mavi-turuncu benekli geckosu tokay, sesli ''to-kay'' çağrısıyla ünlüdür. Renkleri muhteşemdir ama mizacı serttir: savunmacı, hızlı ve güçlü ısırır.","Gözlemlik bir türdür, ''kucak hayvanı'' değildir. Deneyimli bakıcılar için idealdir. Dikey alan ve bol saklanma noktası ister; gece aktiftir."]'::jsonb,'["Isırınca kolay bırakmaz; elle tutmayı sınırlayın","Yüksek nem ve dikey tırmanma alanı şart","Gece sesli olabilir"]'::jsonb,false,18) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('uromastyx','Uromastyx (Dikenli Kuyruk)','Uromastyx spp.','kertenkele','Orta','15–20 yıl','25–40 cm','120×60×45 cm','Güneşlenme 45–55°C! · serin bölge 27–30°C','%20–30 (çok kuru)','Neredeyse tamamen bitkisel: mercimek, yaprak, tohum · böcek çok az','["Çöl kökenli uromastyx, aşırı sıcağı seven ve neredeyse tamamen otçul olan bir kertenkeledir. Güneşlenme noktası diğer sürüngenlerden çok daha yüksek olmalıdır (50°C civarı) — bu türün en kritik bakım detayıdır.","Nem düşmanıdır; nemli ortam solunum ve deri sorunları yapar. Baklagil ve yeşilliklerle beslenir, hayvansal proteine neredeyse hiç ihtiyaç duymaz. Sindirim için güçlü UVB şarttır."]'::jsonb,'["Güneşlenme noktası çok yüksek olmalı (~50°C)","Su kabı gerekmez; nemi besinden alır","Islak/nemli substrat kullanmayın"]'::jsonb,false,19) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('yesil-iguana','Yeşil İguana','Iguana iguana','kertenkele','İleri','15–20 yıl','150–180 cm (kuyrukla)','Oda büyüklüğünde özel kafes','Güneşlenme 35–38°C','%70+','Tamamen bitkisel: koyu yeşillikler, sebze · hayvansal protein zararlı','["Yeşil iguana çok popülerdir ama en çok yanlış bakılan sürüngenlerden biridir: yavruyken 20 cm''dir, yetişkinlikte kuyruğuyla birlikte 1,5 metreyi geçer ve koca bir kafes/oda ister. Bu boyut çoğu evde sorun yaratır.","Kesinlikle otçuldur; hayvansal protein böbrek yetmezliğine yol açar. Güçlü UVB, yüksek nem ve dikey tırmanma alanı şarttır. Ergen erkekler üreme mevsiminde saldırgan olabilir; kuyruk darbesi ve ısırığı ciddidir.","Sahiplenmeden önce yetişkin boyutunu ve 20 yıllık taahhüdü mutlaka düşünün. Uygun bakılmayan iguanalar en çok terk edilen egzotiklerdendir."]'::jsonb,'["Yetişkin boyutu için yer planı şart","Sadece bitkisel beslenir","Güçlü UVB olmadan MBD kaçınılmaz"]'::jsonb,false,20) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('cin-su-ejderi','Çin Su Ejderi','Physignathus cocincinus','kertenkele','Orta–İleri','10–15 yıl','60–90 cm (kuyrukla)','120×60×120 cm dikey + havuz','Güneşlenme 32–35°C','%60–80','Böcek, solucan, balık, az yeşillik','["Güneydoğu Asya''nın yarı-sucul kertenkelesi su ejderi, hem tırmanır hem yüzer. Yeşil iguanaya benzer ama daha küçük ve daha uysaldır. Yüzebileceği bir havuz bölmesi ister.","Cam kenarına burnunu vurup yara yapma (rostral abrazyon) eğilimi vardır; teraryum kenarları görsel bariyerle kapatılmalıdır. Yüksek nem ve dikey tırmanma alanı şarttır."]'::jsonb,'["İçilebilir ve yüzülebilir su bölmesi gerekli","Cam kenar yarası için bariyer koyun","Güçlü UVB ve yüksek nem şart"]'::jsonb,false,21) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('panter-bukalemun','Panter Bukalemun','Furcifer pardalis','kertenkele','İleri','5–7 yıl','35–52 cm','60×60×120 cm tel kafes','Güneşlenme 30–33°C','%50–70, damla sulama','Çekirge, sinek, hamam böceği + kalsiyum','["Madagaskar kökenli panter bukalemun, erkeklerin akıl almaz renkleriyle (Ambilobe, Nosy Be, Sambava lokaliteleri) bukalemunların en gösterişlisidir. Yemen bukalemunundan biraz daha hassastır.","Havalandırmalı tel kafes, damla sulama ve güçlü UVB olmazsa olmazdır. Su kabından içmez, yapraklara damlayan suyu yalar. Elle tutulmayı sevmez, stres hassasiyeti yüksektir."]'::jsonb,'["Otomatik damla/sisleme sistemi kurun","Aynı ortamda iki erkek asla tutulmaz","UVB tüpü 6–12 ayda yenilenmeli"]'::jsonb,false,22) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('savan-monitoru','Savan Monitörü','Varanus exanthematicus','kertenkele','İleri','10–15 yıl','90–120 cm','180×90×60 cm+ özel kafes','Güneşlenme 45–55°C nokta','%50–60, derin nemli substrat','Böcek ağırlıklı: hamam böceği, çekirge, ara sıra kemirgen','["Batı Afrika kökenli savan monitörü güçlü, zeki ve iri bir kertenkeledir. Yavruyken sevimlidir ama hızla büyür ve devasa, kazmaya uygun bir muhafaza ister. Obeziteye çok yatkındır; aşırı kemirgen beslemesi ömrünü kısaltır.","Derin (30+ cm) nemli substratta yuva kazar; bu doğal davranış refahı için şarttır. Güçlü ısı noktası ve büyük alan gerektirdiğinden deneyimli bakıcı işidir."]'::jsonb,'["Böcek ağırlıklı beslenmeli; kemirgeni sınırlayın","Derin kazılabilir substrat şart","Yavru boyutuna aldanmayın; çok büyür"]'::jsonb,false,23) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('kolyeli-kertenkele','Tasmalı (Kolyeli) Kertenkele','Crotaphytus collaris','kertenkele','Orta','5–8 yıl','20–35 cm','90×45×45 cm','Güneşlenme 38–43°C','%30–40','Çekirge, hamam böceği, diğer böcekler','["Kuzey Amerika çöllerinin çevik avcısı tasmalı kertenkele, boynundaki iki siyah bantla tanınır. Erkekler üreme döneminde parlak turkuaz-sarı renklere bürünür. Arka ayakları üzerinde koşabilen nadir kertenkelelerdendir.","Çok aktif ve gündüz avcısıdır; güçlü ışık, yüksek güneşlenme noktası ve geniş taban alanı ister. Gözlemesi keyifli ama elle tutulmaya pek uygun değildir."]'::jsonb,'["Geniş yatay alan ve yüksek ısı noktası","Güçlü UVB gerektirir","Hızlıdır; teraryumdan kaçmasına dikkat"]'::jsonb,false,24) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('kaliforniya-kral-yilani','Kaliforniya Kral Yılanı','Lampropeltis californiae','yilan','Başlangıç','15–20 yıl','90–120 cm','90×45×45 cm','Sıcak bölge 28–30°C · serin 22–24°C','%40–50','Donmuş-çözülmüş fare · 7–10 günde 1','["Kaliforniya kral yılanı, siyah-beyaz bantlı deseniyle mısır yılanı kadar popüler bir başlangıç türüdür. Doğada diğer yılanları bile yediği için tek başına barındırılır — asla iki yılan aynı kutuya konmaz.","Güçlü bir kaçış ustasıdır; kapak mutlaka kilitli olmalıdır. Uysaldır ama açlıkken elini yemle karıştırabilir, bu yüzden maşayla besleme önerilir. Dayanıklı ve az sorun çıkaran bir türdür."]'::jsonb,'["Kesinlikle tek başına; kanibal","Kapak kilidi şart, kaçış ustası","Maşayla besleyin"]'::jsonb,false,25) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('sut-yilani','Süt Yılanı','Lampropeltis triangulum','yilan','Başlangıç–Orta','15–20 yıl','90–150 cm','90×45×45 cm','Sıcak bölge 28–30°C · serin 22–24°C','%40–50','Donmuş-çözülmüş fare · 7–10 günde 1','["Süt yılanı, kırmızı-siyah-sarı bantlarıyla zehirli mercan yılanını taklit eder (zararsız bir blöf — kendisi tamamen zehirsizdir). Kral yılanı akrabasıdır ve benzer bakım ister.","Yavruları biraz sinirli olabilir ama düzenli, nazik elle tutma ile uysallaşır. Saklanmayı çok sever; her iki bölgede saklanma kutusu güven verir. Tek başına barındırılır."]'::jsonb,'["Bol saklanma noktası ister","Yavrular zamanla sakinleşir","Tek başına barındırın"]'::jsonb,false,26) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('kenya-kum-boasi','Kenya Kum Boası','Eryx colubrinus','yilan','Başlangıç','15–20 yıl','40–80 cm (dişi iri)','60×45×30 cm','Sıcak bölge 32–35°C · serin 24–26°C','%30–40','Donmuş-çözülmüş fare · 7–10 günde 1','["Doğu Afrika çöllerinden gelen kum boası, ömrünün çoğunu kuma gömülü pusuda geçiren küçük, tıknaz bir boadır. Az yer kaplaması ve uysallığıyla mükemmel bir başlangıç boasıdır.","Derin (10+ cm) kazılabilir kum/toprak substratı doğal davranışı için şarttır. Alttan ısıtma ile bir taraf sıcak tutulur. Kuru ortam sever; nemli tutulursa deri sorunları çıkar."]'::jsonb,'["Derin, kazılabilir substrat şart","Kuru ortam sever","Gömülü olması normaldir, hastalık değil"]'::jsonb,false,27) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('rosy-boa','Gül Boası (Rosy Boa)','Lichanura trivirgata','yilan','Başlangıç','18–25 yıl','60–90 cm','75×45×30 cm','Sıcak bölge 30–32°C · serin 22–24°C','%30–40','Donmuş-çözülmüş fare · 10–14 günde 1','["Kuzey Amerika kökenli gül boası, boyu kısa, hareketleri yavaş ve mizacı son derece uysal bir türdür. Uzun ömürlü ve az bakım isteyen yapısıyla ideal ilk boalardandır.","Kuru iklim sever, yüksek nem zararlıdır. Yavaş metabolizması sayesinde seyrek beslenir. Nadiren ısırır, elde sakin durur."]'::jsonb,'["Düşük nem şart","Seyrek beslenir; obeziteye dikkat","Çok uysal, ilk yılan için ideal"]'::jsonb,false,28) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('hognose','Domuz Burunlu Yılan (Hognose)','Heterodon nasicus','yilan','Başlangıç–Orta','15–20 yıl','50–90 cm (dişi iri)','75×45×30 cm','Sıcak bölge 30–32°C · serin 24°C','%30–50','Donmuş-çözülmüş fare · 5–7 günde 1','["Yukarı kalkık burnuyla toprağı kazan hognose, tehdit altında kobra gibi boynunu şişirip tıslar, işe yaramazsa sırtüstü dönüp ölü taklidi yapar — tamamen zararsız bir tiyatro. Arka dişlerinde çok hafif bir salgı vardır ama insan için önemsizdir.","Kazmayı sevdiği için derin substrat ister. Sevimli mizacı ve komik savunma davranışlarıyla son yıllarda çok popülerleşti. Yavruların yem başlatması bazen sabır ister."]'::jsonb,'["Derin, kazılabilir substrat","Ölü taklidi ve tıslama blöftür","Yem reddinde sıcaklığı kontrol edin"]'::jsonb,false,29) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('yesil-agac-pitonu','Yeşil Ağaç Pitonu','Morelia viridis','yilan','İleri','15–20 yıl','150–180 cm','60×60×80 cm dikey + yatay tünekler','Gündüz 28–30°C · gece 24–26°C','%60–80','Donmuş-çözülmüş fare/sıçan · 10–14 günde 1','["Yeşil ağaç pitonu, dalda karakteristik ''S'' halkası yapan, göz alıcı yeşil rengiyle bir koleksiyon türüdür. Yavrular sarı veya kırmızı doğar, büyürken yeşile döner (ontogenetik renk değişimi).","Gözlemlik bir türdür; sık elle tutmayı sevmez ve ısırabilir. Hassas nem/sıcaklık dengesi ve dikey tünekler ister. Deneyimli bakıcılar için etkileyici bir türdür."]'::jsonb,'["Yatay tünek dalları şart","Elle tutmayı minimumda tutun","Nem ve sıcaklık dengesi hassas"]'::jsonb,false,30) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('boa-constrictor','Boa Constrictor','Boa constrictor','yilan','Orta–İleri','20–30 yıl','180–300 cm','180×60×60 cm+ (yetişkin)','Sıcak bölge 30–32°C · serin 26–28°C','%50–60','Donmuş-çözülmüş sıçan/tavşan · 10–21 günde 1','["Orta ve Güney Amerika''nın güçlü sıkıcı yılanı boa constrictor, uysal mizacı ve etkileyici boyuyla deneyimli bakıcıların favorisidir. Zehirsizdir; avını sıkarak etkisiz hale getirir.","Yetişkin boyu 2–3 metreyi bulur ve büyük, güçlü bir muhafaza ister. Genelde sakin ve elle tutulabilir olsalar da bu boyuttaki bir yılan, besleme sırasında iki kişilik denetim gerektirir."]'::jsonb,'["Yetişkin boyu için büyük muhafaza planlayın","Besleme sırasında dikkatli olun","Uzun ömür = onlarca yıllık taahhüt"]'::jsonb,false,31) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('hali-pitonu','Halı Pitonu (Carpet Python)','Morelia spilota','yilan','Orta','15–25 yıl','180–250 cm','120×60×90 cm dikey','Sıcak bölge 30–32°C · serin 24–26°C','%50–60','Donmuş-çözülmüş fare/sıçan · 10–14 günde 1','["Avustralya kökenli halı pitonu, muhteşem desenleri ve yarı ağaçsıl yaşamıyla popülerdir. Jungle, Jaguar, Coastal gibi çok sayıda alt tür/morph vardır.","Tırmanmayı sever; dikey alan ve sağlam dallar ister. Yavrular hareketli ve ısırgan olabilir ama düzenli elle tutmayla uysallaşır. Aktif ve gözlemesi keyifli bir türdür."]'::jsonb,'["Dikey tırmanma alanı sağlayın","Yavrular zamanla uysallaşır","Güçlü yeme refleksi; maşayla besleyin"]'::jsonb,false,32) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('kirmizi-yanakli-su-kaplumbagasi','Kırmızı Yanaklı Su Kaplumbağası','Trachemys scripta elegans','kaplumbaga','Yasak','20–30 yıl','20–30 cm','—','—','—','—','["⚠️ YASAL UYARI: Kırmızı yanaklı su kaplumbağası Türkiye''de istilacı tür kabul edilir; satışı ve doğaya salınması 2004''ten beri YASAKTIR. SürüngenMarket''te bu türün satış ilanı yayınlanamaz. Bu içerik yalnızca bilgilendirme ve halihazırda bakanlar içindir.","Fuarlarda küçük ve sevimli satılan bu tür, 20–30 cm''e ulaşır ve büyük bir akvaryum/gölet ister. Sahiplerinin çoğu büyüyünce doğaya bıraktığı için Türkiye''nin sulak alanlarını istila etmiş; yerli çizgili kaplumbağayı tehdit eder hale gelmiştir.","Bakmakta olduğunuz bir bireyi doğaya ASLA bırakmayın — bu hem yasa dışıdır hem ekolojik zarar verir. Büyük filtreli akvaryum, kara/güneşlenme alanı ve güçlü UVB ile ömür boyu bakımı üstlenilmelidir."]'::jsonb,'["Satışı ve doğaya salınması yasaktır","Doğaya bırakmak ekosisteme zarar verir","20–30 cm''e ulaşır; büyük alan ister"]'::jsonb,true,33) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('rus-kaplumbagasi','Rus (Orta Asya) Kaplumbağası','Testudo horsfieldii','kaplumbaga','Orta','40–50+ yıl','15–20 cm','Dış mekan veya 120×60 cm masa','Güneşlenme 32–35°C · UVB şart','%40–50','Yabani otlar, hindiba, deve dikeni · meyve/hayvansal yok','["Orta Asya bozkırlarından gelen Rus kaplumbağası, dört parmaklı ayakları ve güçlü kazma içgüdüsüyle tanınır. Küçük boyu ve dayanıklılığı onu popüler bir kara kaplumbağası yapar; CITES Ek-II''dedir, yalnızca belgeli/üretim bireyler yasaldır.","Aktif bir kazıcıdır; muhafazası kaçışa karşı derin ve güvenli olmalıdır. Lifli yabani yeşilliklerle beslenir, meyve ve marul zararlıdır. Güçlü UVB ve güneşlenme noktası kabuk sağlığı için şarttır."]'::jsonb,'["Güçlü kazıcı; muhafazayı derin yapın","Sadece lifli yeşillik; meyve zararlı","Belgeli/üretim birey olmalı (CITES)"]'::jsonb,false,34) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('kizil-ayakli-kaplumbaga','Kızıl Ayaklı Kaplumbağa','Chelonoidis carbonarius','kaplumbaga','Orta','50+ yıl','30–40 cm','Geniş dış/iç mekan alanı','Güneşlenme 30–33°C','%60–80 (nemli tropik)','Yeşillik + meyve + az miktar protein (omnivor eğilim)','["Güney Amerika tropiklerinden gelen kızıl ayaklı kaplumbağa, bacaklarındaki kırmızı-turuncu pullarla tanınır. Kara kaplumbağalarının çoğundan farklı olarak yüksek nem ister ve az miktarda hayvansal proteine toleranslıdır.","İri boyu ve tropik nem ihtiyacı sebebiyle geniş, nemli ve ısıtılabilir bir alan gerektirir. CITES Ek-II''de listelidir; belgeli üretim bireyler tercih edilmelidir."]'::jsonb,'["Yüksek nem ve ısı ister (tropik)","Ara sıra az protein tolere eder","Geniş alan ve CITES belgesi şart"]'::jsonb,false,35) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('leopar-kaplumbagasi','Leopar Kaplumbağası','Stigmochelys pardalis','kaplumbaga','Orta–İleri','50–80 yıl','40–60 cm','Büyük dış mekan alanı','Güneşlenme 32–35°C','%40–60','Lifli otlar, saman, yeşillik · yüksek lif düşük protein','["Afrika savanlarının benekli devi leopar kaplumbağası, kabuğundaki leopar deseninden adını alır. Çok iri büyür (bazı bireyler 60 cm''i aşar) ve büyük bir bahçe alanı ister; apartman türü değildir.","Otçuldur ve yüksek lif, düşük protein ister; aşırı besleme piramit kabuk deformasyonu yapar. Yaz aylarında dış mekanda doğal güneşle en iyi durumdadır. CITES Ek-II kapsamındadır."]'::jsonb,'["Çok iri büyür; büyük bahçe alanı şart","Yüksek lif, düşük protein","Aşırı besleme kabuk piramitlenmesi yapar"]'::jsonb,false,36) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('kutu-kaplumbagasi','Kutu Kaplumbağası','Terrapene carolina','kaplumbaga','Orta','40–100 yıl','12–18 cm','Dış mekan alanı veya geniş iç mekan','Güneşlenme 29–32°C','%60–80','Omnivor: solucan, böcek, salyangoz + meyve + yeşillik','["Kuzey Amerika kökenli kutu kaplumbağası, alt kabuğundaki menteşe sayesinde kafasını ve bacaklarını tamamen içeri çekip ''kutu gibi'' kapanabilir. Yarı karasaldır ve nemli, gölgeli bir ortam ister.","Omnivordur: hem hayvansal protein hem bitki tüketir. Sığ su kabında ıslanmayı sever. Uzun ömürlüdür; bazı bireyler 100 yaşını görür. CITES Ek-II''dedir."]'::jsonb,'["Nemli, gölgeli ortam ister","Omnivor; çeşitli beslenme şart","Sığ su kabında ıslanır"]'::jsonb,false,37) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('misir-kaplumbagasi','Mısır Kaplumbağası','Testudo kleinmanni','kaplumbaga','İleri / İzne tabi','70–100 yıl','10–14 cm (en küçük tosbağa)','Kontrollü iç mekan / kuru sıcak','Güneşlenme 32–35°C','%20–30 (çok kuru)','Kuru otlar, lifli yeşillik','["⚠️ Mısır kaplumbağası dünyanın en küçük kara kaplumbağalarından biridir ve doğada KRİTİK TEHLİKEDEDİR. CITES Ek-I''de listelidir; ticareti çok sıkı izne tabidir ve yasal belge olmadan alım/satımı yasaktır.","Yalnızca yasal, belgeli üretim bireyler söz konusu olabilir. Aşırı kuru, sıcak ve düşük protein gerektiren hassas bir türdür. Deneyimsiz bakıcı için uygun değildir ve SürüngenMarket''te belgesiz ilanı yayınlanamaz."]'::jsonb,'["CITES Ek-I; belgesiz alım/satım yasak","Doğada kritik tehlikede","Çok kuru ve sıcak ortam ister"]'::jsonb,true,38) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('beyaz-agac-kurbagasi','White''s Ağaç Kurbağası','Litoria caerulea','amfibi','Başlangıç','15–20 yıl','7–11 cm','45×45×60 cm dikey','24–28°C','%60–80','Çekirge, hamam böceği · 2–3 günde 1','["Avustralya kökenli White''s ağaç kurbağası, tombul yapısı ve sürekli ''gülümser'' gibi görünen yüzüyle amfibiler arasında en sevilen başlangıç türüdür. Sakin, dayanıklı ve elle (ıslak elle) kısa süre tutulabilen nadir kurbağalardandır.","Obeziteye çok yatkındır; aşırı besleme sağlığını bozar. Klorsuz suyla nemlendirilmiş dikey teraryum ve tırmanma dalları ister. Gece aktiftir ve düşük sesli ''havlama'' çıkarır."]'::jsonb,'["Obeziteye yatkın; ölçülü besleyin","Sadece klorsuz/şartlandırılmış su","Islak elle ve kısa süre tutun"]'::jsonb,false,39) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('domates-kurbagasi','Domates Kurbağası','Dyscophus spp.','amfibi','Başlangıç–Orta','6–10 yıl','6–10 cm (dişi iri)','45×30×30 cm','24–27°C','%65–80','Çekirge, solucan, hamam böceği · haftada 2–3','["Madagaskar''a özgü domates kurbağası, dişilerin parlak kırmızı-turuncu rengiyle adını alır. Toprağa gömülü pusu kuran, sakin bir türdür. Tehdit altında derisinden yapışkan, tahriş edici bir salgı çıkarır.","Nemli substrat ve sığ su kabı ister. Elle tutulması önerilmez (salgı ve hassas deri). Gözlemlik, gösterişli bir tür arayanlar için idealdir."]'::jsonb,'["Elle tutmaktan kaçının (salgı)","Nemli, kazılabilir substrat","Sığ, klorsuz su kabı"]'::jsonb,false,40) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('zehirli-ok-kurbagasi','Zehirli Ok Kurbağası','Dendrobates spp.','amfibi','Orta–İleri','10–15 yıl','2–5 cm','45×45×45 cm bioaktif dikey','22–26°C','%80–100','Meyve sineği (fruit fly), springtail · günlük','["Orta ve Güney Amerika''nın minik, göz alıcı renkli ok kurbağaları koleksiyoncuların favorisidir. Önemli not: terrryumda üretilen bireyler ZEHİRSİZDİR — zehirlerini doğadaki karınca/böcek diyetinden alırlar, esarette bu diyet olmadığı için zehir üretmezler.","Yüksek nem, canlı bitkili bioaktif teraryum ve minik canlı yem (meyve sineği kültürü) ister. Küçük boyu ve özel yem ihtiyacı sebebiyle biraz deneyim gerektirir ama çok ödüllendiricidir."]'::jsonb,'["Esaret bireyleri zehirsizdir","Meyve sineği kültürü sürekli gerekir","Bioaktif, yüksek nemli teraryum şart"]'::jsonb,false,41) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('afrika-boga-kurbagasi','Afrika Boğa Kurbağası (Pixie)','Pyxicephalus adspersus','amfibi','Orta','15–20 yıl','15–24 cm (çok iri)','60×45 cm alçak','24–28°C','%60–80','Böcek, solucan, ara sıra pinky · iştahı büyük','["Afrika''nın devasa boğa kurbağası, en büyük kurbağa türlerinden biridir ve inanılmaz iştahıyla ünlüdür — önüne gelen her şeyi ısırır. Pacman kurbağasının iri kuzeni gibidir.","Kuru mevsimde toprağa gömülüp kozalaşarak (estivasyon) aylarca uyuyabilir. Güçlü çenesi vardır; maşayla beslenmelidir. Obeziteye çok yatkındır, ölçülü beslenmelidir."]'::jsonb,'["Güçlü ısırır; maşayla besleyin","Obeziteye yatkın; ölçülü besleyin","Nemli, kazılabilir substrat"]'::jsonb,false,42) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('ates-karinli-kurbaga','Ateş Karınlı Kurbağa','Bombina orientalis','amfibi','Başlangıç','10–15 yıl','4–6 cm','45×30 cm yarı-sucul (kara + su)','20–24°C','Yüksek / yarı-sucul','Küçük böcek, meyve sineği, solucan','["Kore ve Çin kökenli ateş karınlı kurbağa, sırtı yeşil, karnı parlak kırmızı-siyah olan küçük, aktif ve gündüz görülebilen bir türdür. Grup halinde tutulabildiği için canlı bir teraryum yaratır.","Yarı-suculdur: hem kara hem sığ su bölmesi ister. Derisinden hafif tahriş edici salgı çıkardığı için tutulduktan sonra eller yıkanmalıdır. Başlangıç için ideal, dayanıklı bir türdür."]'::jsonb,'["Yarı-sucul kurulum (kara + su)","Grup halinde tutulabilir","Tuttuktan sonra elleri yıkayın"]'::jsonb,false,43) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('kaplan-semenderi','Kaplan Semenderi','Ambystoma tigrinum','amfibi','Başlangıç–Orta','10–16 yıl','18–33 cm','60×45 cm karasal, nemli substrat','18–22°C (serin sever)','Yüksek','Solucan, cırcır böceği, ara sıra pinky','["Kuzey Amerika''nın iri karasal semenderi, sarı-siyah kaplan deseniyle tanınır. Aksolotlun karaya çıkmış akrabasıdır; genelde metamorfozunu tamamlar ve toprakta yaşar.","Serin ve nemli ortam ister; yüksek sıcaklık zararlıdır. Kazmayı sever, derin nemli substrat gerekir. İştahlıdır ve obeziteye yatkındır; ölçülü beslenmelidir."]'::jsonb,'["Serin tutun; 24°C üzeri zararlı","Derin nemli substratta kazar","Obeziteye yatkın; ölçülü besleyin"]'::jsonb,false,44) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('ates-semenderi','Ateş Semenderi','Salamandra salamandra','amfibi','İzne tabi / yerli','15–20+ yıl','15–25 cm','Serin, nemli, karasal','15–20°C','Yüksek','Solucan, böcek, salyangoz','["⚠️ Ateş semenderi Türkiye''de doğal olarak bulunan yerli bir türdür ve doğadan toplanması yasa ile korunur. Siyah zemin üzerine sarı desenleriyle çok etkileyicidir ama doğadan yakalanması hem yasa dışı hem ekolojik olarak zararlıdır.","Serin ve nemli orman tabanı ortamı ister; yüksek sıcaklığa çok duyarlıdır. Derisinden tahriş edici salgı çıkarır. Yalnızca yasal/üretim kaynaklı bireyler söz konusu olabilir; doğadan toplanan bireyle ilgilenilmemelidir."]'::jsonb,'["Doğadan toplanması yasaktır (yerli tür)","Çok serin ve nemli ortam ister","Deri salgısı tahriş edicidir; elleri yıkayın"]'::jsonb,true,45) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('sili-gul-tarantula','Şili Gül Tarantulası','Grammostola rosea','eklem','Başlangıç','Dişi 15–20 yıl · erkek 4–6 yıl','12–14 cm bacak açıklığı','30×30 cm yatay','20–26°C','%50–60','Çekirge, hamam böceği · 1–2 haftada 1','["Şili çöllerinden gelen gül tarantulası, sakinliği ve düşük bakım ihtiyacıyla en çok önerilen ilk tarantuladır. Yavaş hareket eder, nadiren tehdit gösterir.","Aylarca yem reddedebilir; bu bu tür için tamamen normaldir, panik gerektirmez. Kuru ortam sever, sığ su kabı yeterlidir. Deri değişiminde sırtüstü yatar — asla dokunulmaz."]'::jsonb,'["Uzun yem oruçları normaldir","Kuru ortam ve sığ su kabı","Düşmesi ölümcül; alçak teraryum"]'::jsonb,false,46) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('mavi-tarantula-gbb','Yeşil Bacaklı Mavi Tarantula (GBB)','Chromatopelma cyaneopubescens','eklem','Başlangıç–Orta','Dişi 12–14 yıl · erkek 4 yıl','13–15 cm bacak açıklığı','30×30 cm','24–28°C','%50–60','Çekirge, hamam böceği · haftada 1','["Venezuela kökenli GBB, metalik mavi bacakları, yeşil karapaksı ve turuncu karnıyla tarantulaların en renklisidir. Bol ağ ördüğü için teraryumunu göz alıcı bir yuvaya çevirir.","Hızlıdır ve hafif savunmacı olabilir ama zehri zararsızdır. Ağ örmeye çok elverişli olduğundan tırmanma noktaları ve orta nemli substrat sever. Görsel açıdan en tatmin edici başlangıç-orta türlerdendir."]'::jsonb,'["Bol ağ örer; tırmanma noktası sağlayın","Hızlıdır; teraryum açarken dikkat","Renkleri her deri değişiminde canlanır"]'::jsonb,false,47) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('asya-orman-akrebi','Asya Orman Akrebi','Heterometrus spp.','eklem','Orta','6–8 yıl','10–15 cm','40×30 cm','25–30°C','%70–80','Çekirge, hamam böceği · haftada 1–2','["İmparator akrebe çok benzeyen Asya orman akrebi, koyu siyah rengi ve iri kıskaçlarıyla tanınır. Zehri arı sokması düzeyindedir; asıl gücü kıskaçlarındadır. İmparator akrepten biraz daha savunmacıdır.","Nemli tropik ortam ve derin, kazılabilir substrat ister. Gece aktiftir. UV ışık altında floresan parlar. Elle tutulması önerilmez."]'::jsonb,'["Elle tutmayın; savunmacı olabilir","Yüksek nem ve derin substrat","Gece aktiftir, gündüz saklanır"]'::jsonb,false,48) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('dev-afrika-salyangozu','Dev Afrika Kara Salyangozu','Achatina / Lissachatina fulica','eklem','Yasak / istilacı','5–10 yıl','20 cm''e kadar kabuk','—','—','—','—','["⚠️ YASAL UYARI: Dünyanın en istilacı 100 türünden biri olan dev Afrika salyangozu, birçok ülkede olduğu gibi Türkiye''de de ciddi tarım ve ekosistem tehdidi kabul edilir; ithalatı ve ticareti kısıtlıdır. Doğaya salınması kesinlikle yasaktır.","Bilgilendirme amaçlı: çok hızlı ürer (tek birey binlerce yavru yapabilir), tarım ürünlerine zarar verir ve insana geçebilen parazit taşıyabilir. SürüngenMarket''te bu türün ilanı yayınlanmaz; bu kayıt yalnızca farkındalık içindir."]'::jsonb,'["İstilacı; ticareti ve salınması yasak","Parazit taşıyabilir, çıplak elle dokunmayın","Doğaya asla bırakılmaz"]'::jsonb,true,49) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('sopa-bocegi','Sopa Böceği (Çubuk Böceği)','Phasmatodea','eklem','Başlangıç','1–2 yıl','Türlere göre 5–30 cm','30×30×40 cm ağ/file kafes','20–26°C','%60–70','Taze böğürtlen, ahududu, meşe, kuşburnu yaprağı','["Kamuflaj ustası sopa böcekleri, bir dala tıpatıp benzeyen görünümleriyle çocuklar ve yeni başlayanlar için mükemmel, düşük maliyetli bir egzotiktir. Bakımı çok kolaydır.","Taze yaprakla beslenir (özellikle böğürtlen yaprağı). Yüksek nem için günlük hafif sisleme yeterlidir. Bazı türler partenogenezle (erkeğe gerek kalmadan) ürer; hızla çoğalabilir."]'::jsonb,'["Taze yaprak sürekli bulundurulmalı","File/ağ kafes ister (tırmanır)","Hızlı çoğalabilir; popülasyonu takip edin"]'::jsonb,false,50) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('madagaskar-hamambocegi','Madagaskar Islık Çalan Hamam Böceği','Gromphadorhina portentosa','eklem','Başlangıç','2–5 yıl','5–7 cm','30×30 cm kapalı kutu','24–29°C','%60–70','Sebze, meyve, kuru mama · omnivor','["Madagaskar''a özgü bu iri, kanatsız hamam böceği, hava deliklerinden hava iterek çıkardığı tıslama/ıslık sesiyle ünlüdür. Isırmaz, sokmaz, hızlı kaçmaz — bu yüzden ilk omurgasız olarak çok uygundur.","Tırmanmayı sever ama pürüzsüz cam kenarları aşamaz (vazelin bariyer ekstra güvence). Kolayca ürer, koloni oluşturur. Çocuklu ailelerde bile güvenli, ilginç bir gözlem hayvanıdır."]'::jsonb,'["Isırmaz/sokmaz; ilk omurgasız için ideal","Cam kenarı tırmanamaz ama kapak yine de şart","Kolayca ürer; koloni büyür"]'::jsonb,false,51) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('chinchilla','Çinçilla','Chinchilla lanigera','memeli','Orta','12–20 yıl','25–35 cm','Çok katlı geniş kafes','15–22°C (sıcağa çok duyarlı!)','Düşük','Çinçilla peleti + bol saman · şekerli/yağlı yem yasak','["And Dağları''ndan gelen çinçilla, dünyanın en yoğun kürküne sahip memelisidir (tek kıl kökünden 50+ kıl çıkar). Bu muhteşem kürk aynı zamanda en büyük zaafıdır: 25°C üzeri sıcakta ısı çarpması riski çok yüksektir.","Serin, kuru ortam ve düzenli ''toz banyosu'' (özel volkanik toz) kürk sağlığı için şarttır — suyla yıkanmaz. Zıplamayı seven, gece aktif ve uzun ömürlü bir hayvandır; şekerli yemler sindirimini bozar."]'::jsonb,'["25°C üzeri tehlikeli; serin tutun","Suyla değil toz banyosuyla temizlenir","Zıplar; yüksek, çok katlı kafes ister"]'::jsonb,false,52) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('degu','Degu','Octodon degus','memeli','Orta','6–9 yıl','25–31 cm (kuyrukla)','Geniş çok katlı kafes + koşu tekeri','20–24°C','Normal','Degu/çinçilla peleti + saman · şeker kesinlikle yasak (diyabet riski)','["Şili kökenli degu, gündüz aktif olan (çoğu kemirgenin aksine) sosyal ve zeki bir hayvandır. Sesli iletişim kurar ve grup halinde yaşamayı sever; tek başına tutulması strese sokar.","Şekere karşı genetik olarak çok hassastır — meyve ve şekerli yem diyabete yol açar. Kemirmeyi ve tırmanmayı sever; sağlam, geniş kafes ve kemirme malzemesi ister. Kuyruğundan asla tutulmaz (deri sıyrılır)."]'::jsonb,'["En az çift halinde tutun (sosyal)","Şeker/meyve yasak (diyabet)","Kuyruğundan tutmayın"]'::jsonb,false,53) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('gine-domuzu','Gine Domuzu (Guinea Pig)','Cavia porcellus','memeli','Başlangıç','5–8 yıl','20–25 cm','Geniş taban alanlı kafes (min 0,7 m²)','18–24°C','Normal','Saman (sınırsız) + C vitaminli pelet + taze sebze','["Gine domuzu, uysal mizacı ve ''wheek'' çağrısıyla çocuklar için en uygun egzotik memelilerden biridir. Sosyaldir; tek başına tutulması önerilmez, en az çift halinde mutludur.","Kendi C vitaminini üretemez (insan gibi) — beslenmesinde taze biber, maydanoz gibi C kaynakları veya takviye şarttır, eksikliği skorbüt yapar. Sürekli saman erişimi diş ve sindirim sağlığı için gereklidir."]'::jsonb,'["C vitamini takviyesi şart","En az çift halinde tutun","Sınırsız saman erişimi sağlayın"]'::jsonb,false,54) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('suriye-hamsteri','Suriye Hamsteri','Mesocricetus auratus','memeli','Başlangıç','2–3 yıl','13–18 cm','Min 100×50 cm taban, tek katlı geniş','20–24°C','Normal','Hamster tohum karışımı + az taze sebze + ara sıra protein','["Suriye (altın) hamsteri en yaygın evcil hamsterdir. Yalnız yaşayan bir hayvandır — doğasında bölgeseldir ve iki hamster aynı kafeste ciddi kavga eder, bu ölümcül olabilir.","Gece aktiftir; sessiz bir koşu tekeri ve yanak keselerine yem saklama davranışı için derin altlık ister. Sık kullanılan küçük kafesler yetersizdir; geniş, tek katlı taban alanı refahı için kritiktir."]'::jsonb,'["Kesinlikle tek başına yaşar","Geniş, tek katlı taban alanı şart","Gece aktiftir; sessiz tekerlek kullanın"]'::jsonb,false,55) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('gerbil','Gerbil (Moğol Çölfaresi)','Meriones unguiculatus','memeli','Başlangıç','3–4 yıl','10–12 cm (+kuyruk)','Derin altlıklı geniş tank (gerbilarium)','20–24°C','Düşük','Gerbil/tohum karışımı + az sebze','["Moğol bozkırından gelen gerbil, çölden geldiği için neredeyse kokusuz ve çok az idrar üreten temiz bir kemirgendir. Sosyaldir; aynı cinsiyetten çift/grup halinde tutulmalıdır.","Tutkulu bir kazıcıdır; sığ kafes yerine derin altlıklı cam tank (gerbilarium) ister ki tünel kazabilsin. Kuyruğunun ucundan asla tutulmaz — deri sıyrılabilir."]'::jsonb,'["Derin altlıkta tünel kazar; tank kullanın","Çift/grup halinde tutun","Kuyruk ucundan tutmayın"]'::jsonb,false,56) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('gelincik-ferret','Yaban Gelinciği (Ferret)','Mustela putorius furo','memeli','İleri','6–10 yıl','35–50 cm','Çok katlı büyük kafes + günlük serbest zaman','15–24°C','Normal','Yüksek etçil: ferret/kaliteli kedi maması, çiğ et · sebze/tahıl sindiremez','["Ferret, binlerce yıldır evcilleştirilmiş, son derece oyuncu ve meraklı bir etçildir. Köpek/kedi gibi sosyaldir; günde birkaç saat kafes dışı oyun ve keşif ister, aksi halde sıkılır.","Zorunlu etçildir; bitki/tahıl sindiremez, beslenmesi yüksek hayvansal protein olmalıdır. Her deliğe girme meraklısıdır, ev ''ferret-güvenli'' hale getirilmelidir. Bazı ülkelerde/bölgelerde bulundurma iznine tabidir — yerel mevzuat kontrol edilmelidir."]'::jsonb,'["Zorunlu etçil; tahıl/sebze veremezsiniz","Günlük kafes dışı oyun şart","Yerel bulundurma kurallarını kontrol edin"]'::jsonb,false,57) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('fennec-tilkisi','Fennek Tilkisi','Vulpes zerda','memeli','İzne tabi / uzman','10–14 yıl','24–41 cm (+kulaklar)','Geniş, kaçış-güvenli alan','Sıcağa dayanıklı, soğuğa hassas','Düşük','Etçil ağırlıklı: et, böcek, az meyve','["⚠️ Sahra çölünün minik, kocaman kulaklı tilkisi fennek, sevimli görünse de EVCİL BİR HAYVAN DEĞİLDİR. CITES Ek-II kapsamındadır; Türkiye''de bulundurulması özel izne tabidir ve uzman bakımı gerektirir.","Çok yüksek enerjili, gece aktif, kazıcı ve kaçış ustasıdır; normal bir evde ihtiyaçları karşılanamaz. Sesli, hiperaktif ve tuvalet eğitimi zordur. Bilgilendirme amaçlı ele alınmıştır; belgesiz alım/satımı yasaktır ve SürüngenMarket''te ilanı yayınlanmaz."]'::jsonb,'["CITES; belgesiz alım/satım yasak","Evcil değildir, uzman bakımı ister","Çok yüksek enerji ve kaçış eğilimi"]'::jsonb,true,58) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('muhabbet-kusu','Muhabbet Kuşu (Budgie)','Melopsittacus undulatus','kus','Başlangıç','7–10 yıl','18 cm','Min 60×40×50 cm kafes + uçuş zamanı','18–26°C','Normal','Kaliteli tohum/pelet karışımı + taze sebze + kepçe (sepia)','["Avustralya kökenli muhabbet kuşu, dünyanın en popüler evcil kuşudur. Sosyal, neşeli ve bazı bireyleri konuşmayı öğrenebilir. Tek başına tutulacaksa çok ilgi ister; ideali en az çift halindedir.","Uçuş için günlük kafes dışı zaman, tırnak/gaga sağlığı için sepya kemiği ve çeşitli tünekler gerekir. Yapışkan olmayan tava kaplamaları (PTFE) kızdığında çıkan gaz kuşlar için ölümcüldür — mutfaktan uzak tutun."]'::jsonb,'["En az çift halinde daha mutlu","PTFE tava dumanı öldürücü; mutfaktan uzak","Günlük uçuş zamanı sağlayın"]'::jsonb,false,59) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('sevda-papagani','Sevda Papağanı (Lovebird)','Agapornis spp.','kus','Başlangıç–Orta','10–15 yıl','13–17 cm','Geniş kafes + uçuş zamanı','18–26°C','Normal','Tohum/pelet + taze sebze-meyve','["Afrika kökenli lovebird, adını eşine düşkünlüğünden alır. Küçük ama çok enerjik ve güçlü gagalı bir papağandır. Renkleri parlaktır; sosyal ve oyuncudur ama bazen inatçı ve bölgesel olabilir.","Çift halinde çok bağlanırlar ama tek elle beslenmiş birey insana daha çok bağlanır. Kemirmeyi sever; sürekli kemirme oyuncağı gerekir. Uçuş ve zihinsel uyarım için günlük etkileşim şarttır."]'::jsonb,'["Güçlü gaga; sağlam oyuncak ister","Günlük etkileşim ve uçuş şart","Bölgesel olabilir; sabırla sosyalleştirin"]'::jsonb,false,60) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('sultan-papagani','Sultan Papağanı (Cockatiel)','Nymphicus hollandicus','kus','Başlangıç','15–20 yıl','30–33 cm','Geniş kafes + uçuş zamanı','18–26°C','Normal','Pelet ağırlıklı + tohum + taze sebze','["Avustralya kökenli sultan papağanı, başındaki sorguç ve yanaklarındaki turuncu benekle tanınır. Uysal, sevecen ve ıslık/melodi öğrenmeye yatkındır; erkekler daha çok ''şarkı söyler''.","Elle beslenmiş bireyler insana çok bağlanır. ''Gece korkusu'' (ani karanlıkta panikle çırpınma) yaşayabilir; gece hafif bir gece lambası yardımcı olur. Toz üreten bir türdür; tozlanmaya duyarlı evlerde hava temizliğine dikkat."]'::jsonb,'["Islık ve melodi öğrenir","Gece korkusu için loş gece ışığı","Toz üretir; havalandırmaya dikkat"]'::jsonb,false,61) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('jako-papagani','Jako (Afrika Gri) Papağanı','Psittacus erithacus','kus','Yasak/İzne tabi','40–60 yıl','30–35 cm','Çok büyük kafes + uçuş odası','18–26°C','Normal','Pelet + sebze/meyve + kabuklu yemiş','["⚠️ YASAL UYARI: Jako papağanı, olağanüstü konuşma ve zeka yeteneğiyle ünlüdür ama doğada aşırı avlanma yüzünden CITES Ek-I''e alınmıştır. Belgesiz alım, satım ve bulundurma YASAKTIR; Türkiye''de kaçak jako operasyonları sıkça haberlere konu olur.","Bilgilendirme amaçlı: 5 yaşındaki bir çocuğun bilişsel düzeyine ulaşabilen, 50+ yıl yaşayan, yoğun zihinsel uyarım isteyen bir türdür. Ancak yalnızca yasal, halkalı ve belgeli bireyler söz konusu olabilir; SürüngenMarket''te belgesiz jako ilanı yayınlanmaz."]'::jsonb,'["CITES Ek-I; belgesiz alım/satım yasak","Yalnızca halkalı/belgeli birey yasaldır","40–60 yıllık taahhüt ve yoğun ilgi ister"]'::jsonb,true,62) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('kanarya','Kanarya','Serinus canaria','kus','Başlangıç','10–15 yıl','12–13 cm','Geniş uçuş kafesi','16–24°C','Normal','Kanarya tohum karışımı + yeşillik + yumurta maması (üreme döneminde)','["Kanarya, yüzyıllardır ötüşü için üretilen klasik kafes kuşudur. Erkekler muhteşem şakır; dişiler sessizdir. Elle etkileşimden çok gözlem ve ötüş için beslenir.","Sakin, tek başına yaşayabilen bir türdür; erkekler kafes komşusuna bile ötüşle rekabet eder. Uçmak için yatay geniş kafes ister. Tüy dökümü döneminde ötüş azalır, bu normaldir."]'::jsonb,'["Ötüş için erkek tercih edilir","Yatay geniş uçuş kafesi ister","Tüy dökümü döneminde ötüş azalır"]'::jsonb,false,63) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('zebra-ispinozu','Zebra İspinozu','Taeniopygia guttata','kus','Başlangıç','5–7 yıl','10 cm','Geniş yatay uçuş kafesi','18–26°C','Normal','İspinoz tohum karışımı + yeşillik + kepçe','["Avustralya kökenli zebra ispinozu, küçük boyu, ''beep'' benzeri sesi ve kolay üremesiyle sevilen bir sürü kuşudur. Elle tutulmaz; en az çift/grup halinde, kendi aralarında yaşamak için mutludur.","Sürekli hareket eder; uçuş için yatay geniş kafes ister. Çok kolay ürer, hızla çoğalabilir — popülasyon kontrolü için üreme sepetini yönetmek gerekir. Gözlemesi keyifli, düşük etkileşimli bir türdür."]'::jsonb,'["Grup/çift halinde tutulur","Yatay uçuş kafesi ister","Çok kolay ürer; üremeyi yönetin"]'::jsonb,false,64) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('ates-skinki','Ateş Skinki','Lepidothyris fernandi','kertenkele','Orta','10–20 yıl','25–37 cm','90×45×45 cm','Güneşlenme 30–33°C · serin 24–26°C','%60–70','Çekirge, solucan, hamam böceği','["Batı Afrika kökenli ateş skinki, yanlarındaki alev kırmızısı ve siyah-beyaz benekli deseniyle en gösterişli skinklerden biridir. Utangaç ve gizlenmeyi seven bir türdür; bol saklanma ve kazılabilir substrat ister.","Nemli orman tabanı ortamı sever. Elle tutulmaya zamanla alışır ama doğası gereği çekingendir. Parlak renkleri sayesinde gözlemlik bir tür arayanlar için idealdir."]'::jsonb,'["Derin, nemli, kazılabilir substrat","Bol saklanma noktası ister","Çekingendir; sabırla sosyalleştirin"]'::jsonb,false,65) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('gunduz-geckosu','Madagaskar Gündüz Geckosu','Phelsuma spp.','kertenkele','Orta','6–10 yıl','12–30 cm (türlere göre)','45×45×60 cm dikey','Güneşlenme 28–30°C','%60–80','Böcek + hazır meyve mama + nektar','["Çoğu geckonun aksine gündüz aktif olan Phelsuma''lar, parlak zümrüt yeşili ve kırmızı desenleriyle göz kamaştırır. Madagaskar kökenlidir ve güçlü UVB ister (gündüz aktif olduğu için).","Yapışkan parmaklarıyla cama tırmanır; hızlı ve atik olduğundan elle tutulmaya uygun değildir, ayrıca derileri çok hassastır (tutulunca yırtılabilir). Gözlemlik, sergilik bir türdür."]'::jsonb,'["Gündüz aktif; güçlü UVB şart","Derisi hassas; elle tutmayın","Nektar/meyve mama sever"]'::jsonb,false,66) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('arjantin-tegusu','Arjantin Kara-Beyaz Tegusu','Salvator merianae','kertenkele','İleri','15–20 yıl','100–140 cm','Oda büyüklüğünde özel muhafaza','Güneşlenme 40–45°C','%60–70','Omnivor: böcek, kemirgen, yumurta, meyve','["Arjantin tegusu, köpek gibi zeki ve sahibine bağlanabilen iri bir kertenkeledir; ''sürüngen köpeği'' olarak anılır. Yavruyken küçüktür ama 1,2 metreyi aşar ve devasa bir muhafaza ister.","Omnivordur, çeşitli beslenir. Kış aylarında brumasyona (aylarca uykuya) girebilir. Zekası ve sakinliği sayesinde iyi sosyalleştirilirse gerçek bir eşlik hayvanı olur ama boyutu ve gücü deneyim gerektirir."]'::jsonb,'["Yetişkin boyu için oda büyüklüğünde alan","Omnivor; dengeli çeşitlilik şart","Kışın brumasyon normaldir"]'::jsonb,false,67) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('yesil-anol','Yeşil Anol','Anolis carolinensis','kertenkele','Başlangıç–Orta','4–6 yıl','12–20 cm','45×45×60 cm dikey bitkili','Güneşlenme 30–32°C','%60–70','Küçük böcek: meyve sineği, minik çekirge, kurtçuk','["Kuzey Amerika kökenli yeşil anol, yeşil-kahve arası renk değiştirebilen (bukalemun değildir!) küçük, atik bir kertenkeledir. Erkekler boğazlarındaki pembe gerdanı (dewlap) açarak gösteri yapar.","Küçük ve hızlıdır; elle tutulmaya uygun değildir, gözlemlik bir türdür. Su kabından içmez, yapraklara sisleme yapılan suyu yalar. Bitkili dikey teraryumda birden fazla dişiyle grup halinde tutulabilir (tek erkek)."]'::jsonb,'["Yapraklara sislenen suyu içer","Küçük boy böcek gerekir","Bir erkek + birkaç dişi tutulabilir"]'::jsonb,false,68) on conflict (slug) do nothing;
insert into public.guides (slug,name,latin,category_slug,level,lifespan,size,habitat,temperature,humidity,diet,body,tips,legal_warning,sort) values ('ackie-monitoru','Ackie Cüce Monitörü','Varanus acanthurus','kertenkele','Orta–İleri','15–20 yıl','60–70 cm','120×60×60 cm, derin substrat','Güneşlenme 45–55°C nokta','%50–60','Böcek ağırlıklı: hamam böceği, çekirge, ara sıra kemirgen','["Avustralya kökenli ackie (dikenli kuyruklu cüce monitör), büyük monitörlerin zekasını ve kişiliğini taşıyan ama yönetilebilir boyutta olan ideal bir ''ilk monitör''dür. Aktif, meraklı ve sosyalleştirilebilir.","Yüksek güneşlenme noktası ve derin, nemli-altında-kuru katmanlı substratta yuva kazma davranışı ister. Böcek ağırlıklı beslenir; aşırı kemirgen obeziteye yol açar. Zekası sayesinde gözlemi çok keyiflidir."]'::jsonb,'["Yüksek ısı noktası (~50°C) şart","Derin kazılabilir substrat","Böcek ağırlıklı besleyin"]'::jsonb,false,69) on conflict (slug) do nothing;
